use std::arch::x86_64::*;

/// Compute L2 (Euclidean) distance between two 128-dimensional vectors
/// Uses AVX-512 for optimal performance on supported CPUs
#[cfg(target_arch = "x86_64")]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);

    // Try AVX-512 first, fall back to AVX2, then scalar
    #[cfg(target_feature = "avx512f")]
    unsafe {
        l2_distance_avx512(a, b)
    }

    #[cfg(all(target_arch = "x86_64", not(target_feature = "avx512f")))]
    unsafe {
        if is_avx512_supported() {
            l2_distance_avx512(a, b)
        } else {
            l2_distance_avx2(a, b)
        }
    }

    #[cfg(not(target_arch = "x86_64"))]
    l2_distance_scalar(a, b)
}

#[cfg(target_arch = "x86_64")]
#[inline(always)]
fn is_avx512_supported() -> bool {
    #[cfg(target_feature = "avx512f")]
    return true;
    #[cfg(not(target_feature = "avx512f"))]
    return false;
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    // Process 16 floats at a time (512 bits = 16 x 32-bit floats)
    // 128 floats = 8 iterations
    let mut sum = _mm512_setzero_ps();

    for i in 0..8 {
        let va = _mm512_loadu_ps(a_ptr.add(i * 16));
        let vb = _mm512_loadu_ps(b_ptr.add(i * 16));
        let diff = _mm512_sub_ps(va, vb);
        sum = _mm512_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum of the 512-bit register
    let result = _mm512_reduce_add_ps(sum);
    result as f64
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx2")]
#[inline]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f64 {
    let a_ptr = a.as_ptr();
    let b_ptr = b.as_ptr();

    // Process 8 floats at a time (256 bits = 8 x 32-bit floats)
    // 128 floats = 16 iterations
    let mut sum = _mm256_setzero_ps();

    for i in 0..16 {
        let va = _mm256_loadu_ps(a_ptr.add(i * 8));
        let vb = _mm256_loadu_ps(b_ptr.add(i * 8));
        let diff = _mm256_sub_ps(va, vb);
        sum = _mm256_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum of the 256-bit register
    let hi = _mm256_extractf128_ps(sum, 1);
    let lo = _mm256_castps256_ps128(sum);
    let sum128 = _mm_add_ps(hi, lo);
    let sum128 = _mm_hadd_ps(sum128, sum128);
    let sum128 = _mm_hadd_ps(sum128, sum128);
    let result = _mm_cvtss_f32(sum128);
    result as f64
}

#[cfg(not(target_arch = "x86_64"))]
fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| {
            let diff = x - y;
            diff * diff
        })
        .sum::<f32>() as f64
}
