use crate::distance::l2_distance;
use std::collections::BinaryHeap;
use std::sync::RwLock;
use std::cmp::Reverse;

pub struct VectorDB {
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vectors = self.vectors.write().unwrap();
        vectors.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut storage = self.vectors.write().unwrap();
        let count = vectors.len();
        storage.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        // Use a max-heap to keep track of top-k results
        // We use Reverse to make BinaryHeap act as a max-heap for distances
        let mut heap: BinaryHeap<(Reverse<OrderedFloat>, u64)> = BinaryHeap::with_capacity(top_k as usize + 1);

        for (id, vec) in vectors.iter() {
            let dist = l2_distance(query, vec);
            let ordered_dist = OrderedFloat(dist);

            if heap.len() < top_k as usize {
                heap.push((Reverse(ordered_dist), *id));
            } else {
                // If this distance is smaller than the max in heap, replace it
                let max_dist = heap.peek().map(|(Reverse(d), _)| d.0).unwrap_or(f64::MAX);
                if dist < max_dist {
                    heap.pop();
                    heap.push((Reverse(ordered_dist), *id));
                }
            }
        }

        // Extract results from heap and sort by distance
        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|(Reverse(dist), id)| SearchResult {
                id,
                distance: dist.0,
            })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(std::cmp::Ordering::Equal));
        results
    }
}

// Helper struct to make f64 comparable
#[derive(Clone, Copy, Debug)]
struct OrderedFloat(f64);

impl PartialEq for OrderedFloat {
    fn eq(&self, other: &Self) -> bool {
        self.0 == other.0
    }
}

impl Eq for OrderedFloat {}

impl PartialOrd for OrderedFloat {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for OrderedFloat {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.0.partial_cmp(&other.0).unwrap_or(std::cmp::Ordering::Equal)
    }
}
"}

