    let impl_type = if is_x86_feature_detected!("avx512f") {
        IMPL_AVX512
    } else if is_x86_feature_detected!("avx2") {
        IMPL_AVX2
    } else {
        IMPL_SCALAR
    };
    DISTANCE_IMPL.store(impl_type, Ordering::Relaxed);
