{"path":"src/db.rs","content":"use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;

pub struct VectorDB {
    // Store vectors contiguously for cache-friendly access
    vectors: RwLock<FlatVectorStorage>,
}

struct FlatVectorStorage {
    ids: Vec<u64>,
    data: Vec<f32>,  // All vectors concatenated (N x 128)
    dim: usize,
}

impl FlatVectorStorage {
    fn new() -> Self {
        Self {
            ids: Vec::new(),
            data: Vec::new(),
            dim: 128,
        }
    }

    fn push(&mut self, id: u64, vector: Vec<f32>) {
        self.ids.push(id);
        self.data.extend(vector);
    }

    fn extend(&mut self, vectors: Vec<(u64, Vec<f32>)>) {
        for (id, vec) in vectors {
            self.ids.push(id);
            self.data.extend(vec);
        }
    }

    #[inline]
    fn len(&self) -> usize {
        self.ids.len()
    }

    #[inline]
    fn get_vector(&self, idx: usize) -> &[f32] {
        let start = idx * self.dim;
        &self.data[start..start + self.dim]
    }

    #[inline]
    fn get_id(&self, idx: usize) -> u64 {
        self.ids[idx]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(FlatVectorStorage::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut storage = self.vectors.write().unwrap();
        storage.push(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut storage = self.vectors.write().unwrap();
        let count = vectors.len();
        storage.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let storage = self.vectors.read().unwrap();
        let n = storage.len();
        let top_k = top_k as usize;

        // Simple top-k selection with heap
        let mut top_k_heap: Vec<(f64, usize)> = Vec::with_capacity(top_k + 1);

        for i in 0..n {
            let vec = storage.get_vector(i);
            let dist = l2_distance(query, vec);

            if top_k_heap.len() < top_k {
                top_k_heap.push((dist, i));
                if top_k_heap.len() == top_k {
                    // Convert to max-heap
                    for j in (0..top_k / 2).rev() {
                        sift_down(&mut top_k_heap, j);
                    }
                }
            } else {
                // If this distance is smaller than the max, replace it
                if dist < top_k_heap[0].0 {
                    top_k_heap[0] = (dist, i);
                    sift_down(&mut top_k_heap, 0);
                }
            }
        }

        // Sort by distance
        top_k_heap.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));

        top_k_heap
            .into_iter()
            .map(|(dist, idx)| SearchResult {
                id: storage.get_id(idx),
                distance: dist,
            })
            .collect()
    }
}

// Max-heap sift down (largest element at root)
#[inline]
fn sift_down(heap: &mut [(f64, usize)], mut idx: usize) {
    let len = heap.len();
    loop {
        let left = 2 * idx + 1;
        let right = 2 * idx + 2;
        let mut largest = idx;

        if left < len && heap[left].0 > heap[largest].0 {
            largest = left;
        }
        if right < len && heap[right].0 > heap[largest].0 {
            largest = right;
        }

        if largest == idx {
            break;
        }

        heap.swap(idx, largest);
        idx = largest;
    }
}
"}

