        let storage = self.vectors.read().unwrap();
        let n = storage.len();
        let top_k = top_k as usize;

        // Collect all distances
        let mut distances: Vec<(f64, usize)> = (0..n)
            .map(|i| {
                let vec = storage.get_vector(i);
                (l2_distance(query, vec), i)
            })
            .collect();

