            distances.truncate(top_k);
        }

        distances.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));

        distances
            .into_iter()
            .map(|(dist, idx)| SearchResult {
                id: storage.get_id(idx),
                distance: dist,
            })
            .collect()
    }
