        self.data.reserve(vectors.len() * 128);
        for (id, vec) in vectors {
            self.ids.push(id);
            self.data.extend(vec);
        }
    }

    #[inline]
    fn len(&self) -> usize {
        self.ids.len()
    }

    #[inline]
    fn get_vector(&self, idx: usize) -> &[f32] {
        let start = idx * 128;
        &self.data[start..start + 128]
    }

    #[inline]
    fn get_id(&self, idx: usize) -> u64 {
        self.ids[idx]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(FlatStorage::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut storage = self.vectors.write().unwrap();
        storage.push(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut storage = self.vectors.write().unwrap();
        let count = vectors.len();
        storage.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let storage = self.vectors.read().unwrap();
        let n = storage.len();
        let top_k = top_k as usize;

        // Parallel computation of distances with local top-k tracking
        let results: Vec<(f64, usize)> = (0..n)
            .into_par_iter()
            .fold(
                || Vec::with_capacity(top_k + 1),
                |mut local_top_k, i| {
                    let vec = storage.get_vector(i);
                    let dist = l2_distance(query, vec);

                    // Insert into local top-k
                    if local_top_k.len() < top_k {
                        local_top_k.push((dist, i));
                        if local_top_k.len() == top_k {
                            local_top_k.sort_unstable_by(|a, b| b.0.partial_cmp(&a.0).unwrap_or(std::cmp::Ordering::Equal));
                        }
                    } else if dist < local_top_k[0].0 {
                        local_top_k[0] = (dist, i);
                        // Sift down to maintain max-heap property
                        let mut idx = 0;
                        while idx < top_k {
                            let left = 2 * idx + 1;
                            let right = 2 * idx + 2;
                            let mut largest = idx;
                            if left < top_k && local_top_k[left].0 > local_top_k[largest].0 {
                                largest = left;
                            }
                            if right < top_k && local_top_k[right].0 > local_top_k[largest].0 {
                                largest = right;
                            }
                            if largest == idx {
                                break;
                            }
                            local_top_k.swap(idx, largest);
                            idx = largest;
                        }
                    }
                    local_top_k
                },
                |mut a, mut b| {
                    // Merge two local top-k arrays
                    a.append(&mut b);
                    a.sort_unstable_by(|x, y| y.0.partial_cmp(&x.0).unwrap_or(std::cmp::Ordering::Equal));
                    a.truncate(top_k);
                    a
                },
            )
            .flatten()
            .collect();

        // Final sort and convert to SearchResult
        let mut results = results;
        results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));
        results.truncate(top_k);

        results
            .into_iter()
            .map(|(dist, idx)| SearchResult {
                id: storage.get_id(idx),
                distance: dist,
            })
            .collect()
    }
}
